function it_inventory_billing_details_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('it_inventory_billing_details');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	// automatic it_inventory_lookup if passed as filterer
	if(Request::val('filterer_it_inventory_lookup')) {
		$_REQUEST['it_inventory_lookup'] = Request::val('filterer_it_inventory_lookup');
	}

	$data = [
		'username' => parseCode('<%%creatorUsername%%>', true),
		'po_no' => Request::val('po_no', ''),
		'po_date' => Request::dateComponents('po_date', '1'),
		'particulars_of_supplier' => Request::val('particulars_of_supplier', ''),
		'item_description' => br2nl(Request::val('item_description', '')),
		'bill_no' => Request::val('bill_no', ''),
		'bill_date' => Request::dateComponents('bill_date', '1'),
		'quantity' => Request::val('quantity', ''),
		'total_invoice_value' => Request::val('total_invoice_value', ''),
		'cost_of_the_asset' => Request::val('cost_of_the_asset', ''),
		'image' => Request::fileUpload('image', [
			'maxSize' => 10240000,
			'types' => 'jpg|jpeg|gif|png|webp',
			'noRename' => false,
			'dir' => '',
			'success' => function($name, $selected_id) {
				Thumbnail::create($name, getThumbnailSpecs('it_inventory_billing_details', 'image', 'tv'));
				Thumbnail::create($name, getThumbnailSpecs('it_inventory_billing_details', 'image', 'dv'));
			},
			'failure' => function($selected_id, $fileRemoved) {
				if(!strlen(Request::val('SelectedID'))) return '';

				/* for empty upload fields, when saving a copy of an existing record, copy the original upload field */
				return existing_value('it_inventory_billing_details', 'image', Request::val('SelectedID'));
			},
		]),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];


	// automatic it_inventory_lookup if passed as filterer
	if(Request::val('filterer_it_inventory_lookup')) {
		$data['it_inventory_lookup'] = Request::val('filterer_it_inventory_lookup');
	}
	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('it_inventory_billing_details', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		it_inventory_billing_details_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function it_inventory_billing_details_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function it_inventory_billing_details_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('it_inventory_billing_details', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: it_inventory_billing_details_before_delete
	if(function_exists('it_inventory_billing_details_before_delete')) {
		$args = [];
		if(!it_inventory_billing_details_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `it_inventory_billing_details` WHERE `it_inventory_biling_details_id`='{$selected_id}'", $eo);

	// hook: it_inventory_billing_details_after_delete
	if(function_exists('it_inventory_billing_details_after_delete')) {
		$args = [];
		it_inventory_billing_details_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='it_inventory_billing_details' AND `pkValue`='{$selected_id}'", $eo);
}

function it_inventory_billing_details_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('it_inventory_billing_details', $selected_id, 'edit')) return false;

	$data = [
		'po_no' => Request::val('po_no', ''),
		'po_date' => Request::dateComponents('po_date', ''),
		'particulars_of_supplier' => Request::val('particulars_of_supplier', ''),
		'item_description' => br2nl(Request::val('item_description', '')),
		'bill_no' => Request::val('bill_no', ''),
		'bill_date' => Request::dateComponents('bill_date', ''),
		'quantity' => Request::val('quantity', ''),
		'total_invoice_value' => Request::val('total_invoice_value', ''),
		'cost_of_the_asset' => Request::val('cost_of_the_asset', ''),
		'image' => Request::fileUpload('image', [
			'maxSize' => 10240000,
			'types' => 'jpg|jpeg|gif|png|webp',
			'noRename' => false,
			'dir' => '',
			'id' => $selected_id,
			'success' => function($name, $selected_id) {
				Thumbnail::create($name, getThumbnailSpecs('it_inventory_billing_details', 'image', 'tv'));
				Thumbnail::create($name, getThumbnailSpecs('it_inventory_billing_details', 'image', 'dv'));
			},
			'removeOnRequest' => true,
			'remove' => function($selected_id) {
				// do nothing: preserve removed files on server.
			},
			'failure' => function($selected_id, $fileRemoved) {
				if($fileRemoved) return '';
				return existing_value('it_inventory_billing_details', 'image', $selected_id);
			},
		]),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('it_inventory_billing_details', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: it_inventory_billing_details_before_update
	if(function_exists('it_inventory_billing_details_before_update')) {
		$args = ['old_data' => $old_data];
		if(!it_inventory_billing_details_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'it_inventory_billing_details',
		backtick_keys_once($set),
		['`it_inventory_biling_details_id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="it_inventory_billing_details_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('it_inventory_billing_details', $data['selectedID'], calculated_fields()['it_inventory_billing_details']);

	// hook: it_inventory_billing_details_after_update
	if(function_exists('it_inventory_billing_details_after_update')) {
		if($row = getRecord('it_inventory_billing_details', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['it_inventory_biling_details_id'];
		$args = ['old_data' => $old_data];
		if(!it_inventory_billing_details_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('it_inventory_billing_details', $selected_id);
}

